import React, { useState } from "react";

function Subscribe() {
  const [form, setForm] = useState({
    hospitalName: "",
    type: "doctor",
    name: "",
    specialty: "",
    price: "",
    location: "",
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const submit = async () => {
  try {
    const res = await fetch("http://localhost:5000/api/subscription", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(form),
    });

    const data = await res.json();

    if (!res.ok) {
      throw new Error(data.error || "Something went wrong");
    }

    alert(data.message || "Submitted successfully");
  } catch (err) {
    console.error(err);
    alert(err.message);
  }
};

  return (
    <div className="subscribe-page">
      <h2>Join HEALink Network</h2>

      <input name="hospitalName" placeholder="Hospital Name" onChange={handleChange} />

      <select name="type" onChange={handleChange}>
        <option value="doctor">Doctor</option>
        <option value="medicine">Medicine</option>
        <option value="test">Test</option>
        <option value="blood">Blood Bank</option>
      </select>

      <input name="name" placeholder="Name" onChange={handleChange} />
      <input name="specialty" placeholder="Specialty (if doctor)" onChange={handleChange} />
      <input name="price" placeholder="Price" onChange={handleChange} />
      <input name="location" placeholder="Location" onChange={handleChange} />

      <button onClick={submit}>Submit</button>
    </div>
  );
}

export default Subscribe;
